,"            display: flex;","            gap: 20px;","            justify-content: center;","        }","        nav li {","            position: relative;","            cursor: pointer;","            transition: color 0.3s ease, transform 0.3s ease;","        }","        nav li:hover {","            color: #007BFF;","            transform: scale(1.1);","        }","        /* 下拉菜单样式 */","        .dropdown-menu {","            display: none;","            position: absolute;","            top: 100%;","            left: 0;","            background: #fff;","            padding: 10px 0;","            box-shadow: 0 2px 8px rgba(0,0,0,0.15);","            min-width: 150px;","            z-index: 1000;","        }","        .dropdown-menu li {","            padding: 8px 20px;","            white-space: nowrap;","            transition: background-color 0.3s ease;","        }","        .dropdown-menu li:hover {","            background-color: #f2f2f2;","        }","        /* 鼠标悬停时显示下拉菜单 */","        nav li:hover .dropdown-menu {","            display: block;","        }","        ","        /* 主体商品网格样式：每行显示三个产品 */","        .product-grid {","            display: grid;","            grid-template-columns: repeat(3, 1fr);","            gap: 20px;","            padding: 20px;","            box-sizing: border-box;","            max-width: 1200px;","            margin: 0 auto;","        }","        .product-item {","            border: 1px solid #ccc;","            padding: 10px;","            text-align: center;","            background-color: #fff;","        }","        .product-item img {","            width: 200px;","            height: 200px;","            object-fit: cover;","            margin-bottom: 10px;","            transition: transform 0.3s ease;","        }","        .product-item img:hover {","            transform: scale(1.05);","        }","        .product-item h3 {","            font-size: 16px;","            margin: 5px 0;","        }","        .product-item p {","            margin: 5px 0;","        }","    </style>","</head>","<body>","","    <!-- 顶部搜索栏、Logo、购物车/个人图标 -->","    <header>","        <div class=\"search-container\">","            <input type=\"text\" placeholder=\"Search for Anything\">","        </div>","        <div class=\"logo\">","            <img src=\"logo_final.png\" alt=\"Normal Market Logo\">","        </div>","        <div class=\"user-cart\">","            <span>🛒</span>","            <span>👤</span>","        </div>","    </header>","","    <!-- 导航栏：Home, Freeze, Fresh, Drink, Pet, Household -->","    <nav>","        <ul>","            <li>Home</li>","            <li>","                Freeze","                <ul class=\"dropdown-menu\">","                    <li>Fast Food</li>","                    <li>Meat</li>","                    <li>Fruits and Vegetables</li>","                    <li>Ice Cream</li>","                </ul>","            </li>","            <li>","                Fresh","                <ul class=\"dropdown-menu\">","                    <li>Meat</li>","                    <li>Vegetable</li>","                    <li>Seafood</li>","                    <li>Fruits</li>","                    <li>spice</li>","                </ul>","            </li>","            <li>","                Drink","                <ul class=\"dropdown-menu\">","                    <li>Soft Drink</li>","                    <li>water</li>","                    <li>Dairy</li>","                    <li>Alcohol</li>","                </ul>","            </li>","            <li>","                Pet","                <ul class=\"dropdown-menu\">","                    <li>Dog</li>","                    <li>Cat</li>","                    <li>Others</li>","                </ul>","            </li>","            <li>","                Household","                <ul class=\"dropdown-menu\">","                    <li>Kitchen</li>","                    <li>Bathroom</li>","                    <li>Electrical Equipment</li>","                </ul>","            </li>","        </ul>","    </nav>","","    <!-- 主体内容：产品网格 -->","    <main>","        <div class=\"product-grid\">","            <?php","            if ($result && $result->num_rows > 0) {","                // 循环输出产品数据","                while ($row = $result->fetch_assoc()) {","                    // 根据产品名称生成图片文件名：将空格替换为下划线并加 .png","                    $imgFile = str_replace(\" \", \"_\", $row[\"product_name\"]) . \".png\";","                    echo '<div class=\"product-item\">';","                    echo '<img src=\"' . htmlspecialchars($imgFile) . '\" alt=\"' . htmlspecialchars($row[\"product_name\"]) . '\">';","                    echo '<h3>' . htmlspecialchars($row[\"product_name\"]) . '</h3>';","                    // 显示价格和单位，例如 \"$40.00 1KG\"","                    echo '<p>$' . number_format($row[\"unit_price\"], 2) . ' ' . htmlspecialchars($row[\"unit_quantity\"]) . '</p>';","                    // 检测库存状态：in_stock 不为0显示 \"in stock\"，否则显示 \"out of stock\"","                    echo '<p>' . (($row[\"in_stock\"] != 0) ? \"in stock\" : \"out of stock\") . '</p>';","                    echo '</div>';","                }","            } else {","                echo '<p style=\"text-align:center;\">No products found.</p>';","            }","            ?>","        </div>","    </main>","","</body>","</html>",""]}]]},"ace":{"folds":[],"scrolltop":1800,"scrollleft":0,"selection":{"start":{"row":115,"column":26},"end":{"row":115,"column":26},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":0},"timestamp":1743956049007,"hash":"a4735fee8d4f14c1da0301b132e0146e1ddad007"}